#include<bits/stdc++.h>
using namespace std;

int n, k;
string a;
long long dp[8][54];
long long jia(int l, int r) {
	long long res = 0;
	for (int i = l - 1; i <= r - 1; i++) {
		res = res * 10 + (a[i] - '0');
	}
	return res;
}

int main() {
	cin >> n >> k >> a;
	for (int j = 1; j <= n; j++) {
		dp[0][j] = jia(1, j);
	}
	for (int i = 1; i <= k; i++) {
		for (int j = i + 1; j <= n; j++) {
			dp[i][j] = 0;
			for (int m = i; m < j; m++) {
				long long t = dp[i - 1][m] * jia(m + 1, j);
				if (t > dp[i][j]) {
					dp[i][j] = t;
				}
			}
		}
	}
	cout << dp[k][n] << "\n";
	return 0;
}
